using QBEngineer.Core.Entities;
using QBEngineer.Core.Enums;
using QBEngineer.Data.Context;

using Serilog;

namespace QBEngineer.Api.Data.TrainingContent;

public class EventsTraining : TrainingContentBase
{
    public EventsTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Events Overview",
            Slug = "events-overview",
            Summary = "What events are, the four event types, attendee management, RSVP workflow, and automatic reminders.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/admin/events"]""",
            Tags = """["events","admin","meetings","training","safety"]""",
            ContentJson = """{"body":"## Events Overview\n\nThe Events module lets administrators and managers schedule and track company events — meetings, training sessions, safety briefings, and other gatherings. It lives under Admin > Events and provides a central calendar of everything happening in your organization.\n\n### Event Types\n\nEvery event is categorized into one of four types:\n- **Meeting** — team meetings, project reviews, stand-ups, 1-on-1s. Icon: groups.\n- **Training** — skills training, onboarding sessions, certification prep. Icon: school.\n- **Safety** — safety briefings, emergency drills, compliance reviews. Icon: health_and_safety.\n- **Other** — company socials, announcements, facility tours, or anything that doesn't fit the above. Icon: event.\n\nThe type determines the icon shown in the events table and helps with filtering.\n\n### Attendees and RSVP\n\nWhen creating or editing an event, you select attendees from the list of active employees. Each attendee receives a notification inviting them to the event. Attendees can then respond with one of these statuses:\n- **Invited** — default status, no response yet\n- **Accepted** — attendee confirmed they will attend\n- **Declined** — attendee cannot attend\n- **Attended** — post-event confirmation that the person was present (useful for compliance tracking)\n\nThe attendee count is shown in the events table so you can see at a glance how many people are invited to each event.\n\n### Required vs Optional Events\n\nEvents can be marked as Required Attendance. When toggled on:\n- The invitation notification is sent with warning severity instead of info\n- The events table shows a yellow Required chip next to the event\n- This signals to employees and managers that attendance is mandatory (e.g., safety briefings, compliance training)\n\nOptional events show as plain text in the table.\n\n### Automatic Reminders\n\nThe system runs a background job that sends reminder notifications 15 minutes before an event starts. This ensures attendees don't miss upcoming events, even if they didn't check the original invitation. The reminder is sent once — the ReminderSentAt timestamp on the event prevents duplicate notifications.\n\n### Where Events Appear\n\n- **Admin > Events** — the main management view where admins create, edit, filter, and cancel events\n- **Shop Floor Display** — upcoming events appear in the shop floor's upcoming section so production workers see what's scheduled\n- **Employee Detail** — each employee's profile has an Events tab showing events they're invited to or have attended\n\n### Cancelling Events\n\nEvents are soft-cancelled, not deleted. When you cancel an event, the IsCancelled flag is set and the event no longer appears in the default list view. Cancelled events are excluded from the events query, keeping the table clean while preserving the historical record.\n\n### When to Use Events\n\n- Scheduling a team meeting or project review\n- Organizing mandatory safety briefings or emergency drills\n- Planning training sessions for new hires or skill development\n- Tracking attendance for compliance purposes (who attended which safety training)\n- Announcing company-wide gatherings or social events","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Events — Guided Tour",
            Slug = "events-walkthrough",
            Summary = "A guided tour of Admin > Events: filtering by type, creating events, managing attendees, and cancelling events.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/admin/events"]""",
            Tags = """["events","admin","walkthrough"]""",
            ContentJson = """{"appRoute":"/admin/events","startButtonLabel":"Tour Events","steps":[{"element":"[data-testid='new-event-btn']","popover":{"title":"New Event Button","description":"Click here to create a new event. You'll enter the title, type, date/time range, location, description, attendees, and whether attendance is required. Attendees receive a notification immediately upon creation.","side":"bottom"}},{"element":".panel-header app-select","popover":{"title":"Type Filter","description":"Filter events by type: Meeting, Training, Safety, or Other. Select a type to narrow the table, or choose All to see everything. The filter updates the table in real time.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Events Table","description":"Lists all active (non-cancelled) events sorted by start time. Columns include Title, Type (with icon chip), Start/End times, Location, Attendee count, and Required status. Click column headers to sort. Use the gear icon to customize visible columns.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Events Field Reference",
            Slug = "events-field-reference",
            Summary = "Complete reference for every field, button, event type, attendee status, validation rule, and action in Events.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 3,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/admin/events"]""",
            Tags = """["events","admin","reference"]""",
            ContentJson = """{"title":"Events Field Reference","groups":[{"heading":"Event Form Fields","items":[{"label":"Title (required)","value":"Text input, max 200 characters. The name of the event shown in the table, notifications, and attendee views. Examples: 'Weekly Safety Briefing', 'Q2 Project Review', 'New Hire Orientation'. data-testid: event-title"},{"label":"Event Type (required)","value":"Dropdown: Meeting, Training, Safety, Other. Determines the icon chip shown in the table and enables type-based filtering. Default: Meeting. data-testid: event-type"},{"label":"Location","value":"Text input, optional, max 200 characters. Physical or virtual location (e.g., 'Conference Room B', 'Shop Floor Bay 3', 'Zoom link in description'). data-testid: event-location"},{"label":"Start Date (required)","value":"Date picker. The date the event begins. Combined with Start Time to form the full start timestamp. data-testid: event-start-date"},{"label":"Start Time (required)","value":"Text input, HH:MM format (24-hour). The time the event begins. Default: 09:00. Combined with Start Date. data-testid: event-start-time"},{"label":"End Date (required)","value":"Date picker. The date the event ends. For single-day events, same as Start Date. data-testid: event-end-date"},{"label":"End Time (required)","value":"Text input, HH:MM format (24-hour). Must result in an end timestamp after the start timestamp. Default: 10:00. data-testid: event-end-time"},{"label":"Description","value":"Textarea, optional, max 2000 characters. Agenda, preparation instructions, or additional context. data-testid: event-description"},{"label":"Attendees","value":"Multi-select dropdown populated with all active employees (displayed as Last, First). Selected users receive an invitation notification when the event is created."},{"label":"Required Attendance","value":"Toggle switch. When ON, marks the event as mandatory. Notification severity changes from info to warning. A yellow 'Required' chip appears in the table. data-testid: event-required"}]},{"heading":"Attendee Fields","items":[{"label":"User","value":"The employee invited to the event. Displayed as Last, First format."},{"label":"Status","value":"Current RSVP status: Invited (default), Accepted, Declined, or Attended."},{"label":"Responded At","value":"Timestamp of when the attendee last changed their RSVP status. Null if still in Invited status (no response yet)."}]},{"heading":"Event Types","items":[{"label":"Meeting","value":"Icon: groups. Team meetings, project reviews, stand-ups, 1-on-1s, and other collaborative sessions."},{"label":"Training","value":"Icon: school. Skills training, onboarding, certification prep, and educational sessions."},{"label":"Safety","value":"Icon: health_and_safety. Safety briefings, emergency drills, compliance reviews, and hazard training."},{"label":"Other","value":"Icon: event. Company socials, announcements, facility tours, and anything not covered by the other types."}]},{"heading":"Attendee Statuses","items":[{"label":"Invited","value":"Default status assigned when an attendee is added to an event. Indicates no response has been given yet."},{"label":"Accepted","value":"Attendee has confirmed they will attend the event."},{"label":"Declined","value":"Attendee has indicated they cannot attend the event."},{"label":"Attended","value":"Post-event status confirming the person was physically present. Used for compliance tracking (e.g., proving safety training attendance)."}]},{"heading":"Buttons and Actions","items":[{"label":"New Event (primary button)","value":"Opens the event creation dialog. All fields reset to defaults (type: Meeting, time: 09:00–10:00, not required). data-testid: new-event-btn"},{"label":"Save / Create Event (dialog)","value":"Creates or updates the event. Disabled when form is invalid or save is in progress. Hover shows validation popover if disabled. On create, notifications are sent to all selected attendees. data-testid: event-save-btn"},{"label":"Cancel (dialog)","value":"Closes the dialog without saving changes."},{"label":"Edit (row icon)","value":"Pencil icon on each table row. Opens the edit dialog pre-filled with the event's current values including attendees."},{"label":"Cancel Event (row icon)","value":"Red X icon on each table row. Opens a confirmation dialog. Confirming soft-cancels the event (sets IsCancelled flag). The event disappears from the table but the record is preserved."},{"label":"Type Filter (header)","value":"Dropdown in the panel header. Filters the table by event type. Options: All, Meeting, Training, Safety, Other."}]},{"heading":"Validation Rules","items":[{"label":"Title","value":"Required. Cannot be empty. Maximum 200 characters."},{"label":"Event Type","value":"Required. Must be one of: Meeting, Training, Safety, Other."},{"label":"Start Date","value":"Required. Must be a valid date."},{"label":"Start Time","value":"Required. Must be in HH:MM format."},{"label":"End Date","value":"Required. Must be a valid date."},{"label":"End Time","value":"Required. The combined end date/time must be after the combined start date/time."},{"label":"Description","value":"Optional. Maximum 2000 characters."},{"label":"Location","value":"Optional. Maximum 200 characters."},{"label":"Attendees","value":"Optional. Zero or more active employees. Duplicates are automatically removed."},{"label":"Submit button popover","value":"When form is invalid, hovering over Save/Create shows a validation popover listing which fields need attention (e.g., 'Title is required', 'Start Date is required')."}]},{"heading":"Table Columns","items":[{"label":"Title","value":"Sortable. The event name."},{"label":"Type","value":"Sortable, filterable (enum). Shows a chip with the type icon: groups (Meeting), school (Training), health_and_safety (Safety), event (Other)."},{"label":"Start","value":"Sortable, date type. Formatted MM/dd/yyyy hh:mm a. Width: 160px."},{"label":"End","value":"Sortable, date type. Formatted MM/dd/yyyy hh:mm a. Width: 160px."},{"label":"Location","value":"Sortable. Physical or virtual location text. Width: 150px."},{"label":"Attendees","value":"Sortable, number type. Count of invited attendees. Width: 100px."},{"label":"Required","value":"Sortable. Shows yellow 'Required' chip if mandatory, otherwise muted 'Optional' text. Width: 90px."},{"label":"Actions","value":"Edit (pencil) and Cancel (X) icon buttons. Width: 80px."}]},{"heading":"Notifications and Reminders","items":[{"label":"Invitation Notification","value":"Sent to each attendee when an event is created. Format: '{Creator Name} invited you to \"{Event Title}\" on {MM/dd/yyyy hh:mm tt}.' Severity: warning if required, info if optional."},{"label":"15-Minute Reminder","value":"A Hangfire background job sends reminder notifications 15 minutes before the event starts. Sent once — the ReminderSentAt timestamp prevents duplicates."},{"label":"Cancellation","value":"When an event is cancelled, the record is soft-deleted (IsCancelled flag). Attendees are notified of the cancellation."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Events Knowledge Check",
            Slug = "events-quiz",
            Summary = "Test your knowledge of the Events module: types, attendees, RSVP statuses, reminders, and admin workflows.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/admin/events"]""",
            Tags = """["events","admin","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"ev1","text":"You need to schedule a mandatory safety briefing for all shop floor workers next Tuesday. Where do you create this event?","options":[{"id":"a","text":"Dashboard > Calendar widget > click the date"},{"id":"b","text":"Admin > Events > click New Event, set type to Safety, toggle Required Attendance ON","isCorrect":true},{"id":"c","text":"Time Tracking > create a new time entry with category 'Safety'"},{"id":"d","text":"Shop Floor Display > Upcoming section > Add Event"}],"explanation":"Events are created in Admin > Events. Click New Event, select type Safety, fill in the details, select attendees, and toggle Required Attendance ON. The yellow Required chip will appear in the table, and attendees receive a warning-level notification."},{"id":"ev2","text":"What are the four event types available in the system?","options":[{"id":"a","text":"Urgent, Standard, Optional, Recurring"},{"id":"b","text":"Meeting, Training, Safety, Other","isCorrect":true},{"id":"c","text":"Internal, External, Virtual, Hybrid"},{"id":"d","text":"Daily, Weekly, Monthly, Annual"}],"explanation":"The four event types are Meeting (groups icon), Training (school icon), Safety (health_and_safety icon), and Other (event icon). Each type has a distinct icon shown as a chip in the events table."},{"id":"ev3","text":"An employee has been invited to an event but hasn't responded yet. What is their attendee status?","options":[{"id":"a","text":"Pending"},{"id":"b","text":"No Response"},{"id":"c","text":"Invited","isCorrect":true},{"id":"d","text":"Unconfirmed"}],"explanation":"The default status for a newly added attendee is Invited. It remains Invited until the employee responds. The four possible statuses are: Invited, Accepted, Declined, and Attended."},{"id":"ev4","text":"After a safety training session, you need to record who actually showed up. Which attendee status should you set for each person who was present?","options":[{"id":"a","text":"Accepted — they already confirmed beforehand"},{"id":"b","text":"Attended — this confirms physical presence for compliance tracking","isCorrect":true},{"id":"c","text":"Completed — marks the training as done"},{"id":"d","text":"Present — checked-in status"}],"explanation":"The Attended status is specifically designed for post-event confirmation of physical presence. This is critical for compliance tracking — proving that employees actually attended required safety or training sessions, not just that they accepted the invitation."},{"id":"ev5","text":"How does the system remind attendees about upcoming events?","options":[{"id":"a","text":"An email is sent 1 hour before the event starts"},{"id":"b","text":"A push notification is sent to their mobile device"},{"id":"c","text":"A Hangfire background job sends a notification 15 minutes before the event starts","isCorrect":true},{"id":"d","text":"No automatic reminders — attendees must check the calendar themselves"}],"explanation":"The system runs a Hangfire background job that sends reminder notifications 15 minutes before an event's start time. The ReminderSentAt timestamp on the event record prevents duplicate reminders from being sent."},{"id":"ev6","text":"You want to cancel a scheduled event. What happens when you click the cancel (X) icon on an event row?","options":[{"id":"a","text":"The event record is permanently deleted from the database"},{"id":"b","text":"A confirmation dialog appears, and confirming soft-cancels the event — it disappears from the table but the record is preserved","isCorrect":true},{"id":"c","text":"The event is moved to an archive section at the bottom of the page"},{"id":"d","text":"All attendees are removed but the event stays visible in the table"}],"explanation":"Cancelling an event is a soft operation. A confirmation dialog asks 'Cancel Event?' and warns that attendees will be notified. Confirming sets the IsCancelled flag on the event. It no longer appears in the default table view, but the historical record is preserved."},{"id":"ev7","text":"What's the difference between a Required and an Optional event?","options":[{"id":"a","text":"Required events block the attendee's calendar; optional events don't"},{"id":"b","text":"Required events show a yellow Required chip in the table, and invitation notifications are sent with warning severity instead of info","isCorrect":true},{"id":"c","text":"Required events can only be created by admins; optional events can be created by anyone"},{"id":"d","text":"There is no functional difference — it's just a label"}],"explanation":"When Required Attendance is toggled ON, two things change: the invitation notification is sent with warning severity (instead of info), making it stand out in the notifications panel, and a yellow Required chip appears next to the event in the table for visual emphasis."},{"id":"ev8","text":"You're looking at the events table and want to see only Training events. How do you filter?","options":[{"id":"a","text":"Click the Training column header to sort by type"},{"id":"b","text":"Use the Type filter dropdown in the panel header and select Training","isCorrect":true},{"id":"c","text":"Type 'Training' in the search box"},{"id":"d","text":"Right-click the table and select Filter > Training"}],"explanation":"The Type filter dropdown in the events panel header lets you filter by event type. Select Training to see only training events. The filter updates the table in real time by re-querying the API with the selected type."},{"id":"ev9","text":"When creating an event, the Save button is disabled and you hover over it to see a popover. What does the popover show?","options":[{"id":"a","text":"A loading spinner indicating the save is in progress"},{"id":"b","text":"A tooltip saying 'Form is not valid'"},{"id":"c","text":"A bulleted list of validation violations — which specific fields need attention (e.g., 'Title is required', 'Start Date is required')","isCorrect":true},{"id":"d","text":"Nothing — the button simply can't be clicked when disabled"}],"explanation":"The validation popover pattern is used throughout QB Engineer. When the form is invalid, hovering over the disabled Save button shows a bulleted list of exactly which fields have issues. This replaces inline error messages beneath each field."},{"id":"ev10","text":"Where else in the application do events appear besides the Admin > Events page?","options":[{"id":"a","text":"Only on Admin > Events — events are an admin-only feature"},{"id":"b","text":"On the Shop Floor Display's upcoming section and in each employee's Events tab in their profile","isCorrect":true},{"id":"c","text":"On the Dashboard calendar widget and the Kanban board sidebar"},{"id":"d","text":"In the Chat module as automated event announcements"}],"explanation":"Events appear in three places: Admin > Events (main management view), the Shop Floor Display (upcoming events section so production workers see what's scheduled), and the Employee Detail view (Events tab showing events each person is invited to or has attended)."}]}"""
        });

        Log.Information("Seeded Events training modules");
